class Logger {
private:
    std::queue<std::string> logs;
    std::mutex mtx;
    std::condition_variable cv;
    bool stop = false;

public:
    void log(const std::string &message) {
        mtx.lock();
        logs.push(message);
        mtx.unlock();
        cv.notify_one();
    }

    void processLogs() {
        while (true) {
            mtx.lock();
            if (!logs.empty()) {
                std::string msg = logs.front();
                logs.pop();
                mtx.unlock();
                std::cout << msg << std::endl;
            } else if (stop) {
                mtx.unlock();
                break;
            } else {
                mtx.unlock();
                std::this_thread::sleep_for(std::chrono::milliseconds(100));
            }
        }
    }

    void shutdown() {
        mtx.lock();
        stop = true;
        mtx.unlock();
        cv.notify_all();
    }
};

function calculateTotal(prices, taxRate) {
  var t = 0;
  var i = 0;
  for(i=0; i < prices.length; i++) {
    t = t + prices[i];
  }
  var totalPrice = t + (t * taxRate);
  return totalPrice.toFixed(2);
}

